      setApiMessage('Utilizador criado com sucesso. Já pode iniciar sessão com as credenciais definidas.');
    } catch (error) {
      setApiMessage(error.response?.data?.message || 'Não foi possível criar o utilizador.');
    }
  };

  const addManager = async () => {
    if (!newManagerData.name.trim() || !newManagerData.username.trim() || !newManagerData.password.trim()) return;
    try {
      const response = await api.post('/users/managers', {
        nome: newManagerData.name.trim(),
        username: newManagerData.username.trim(),
        password: newManagerData.password.trim(),
        email: newManagerData.email.trim(),
        telefone: newManagerData.phone.trim(),
        departamento: newManagerData.department.trim(),
        teamSize: newManagerData.teamSize,
      });
      setManagers((current) => [response.data.data, ...current]);
      setNewManagerData({ name: '', username: '', password: '', email: '', phone: '', department: '', teamSize: '' });
      setShowAddManagerDialog(false);
      setApiMessage('Gestor criado com sucesso. Já pode iniciar sessão com as credenciais definidas.');
    } catch (error) {
      setApiMessage(error.response?.data?.message || 'Não foi possível criar o gestor.');
    }
  };

  const deleteUser = async (id) => {
    try {
      await api.delete(`/users/${id}`);
      setUsers((current) => current.filter((entry) => entry.id !== id));
      setApiMessage('Utilizador eliminado com sucesso.');
    } catch (error) {
      setApiMessage(error.response?.data?.message || 'Não foi possível eliminar o utilizador.');
    }
  };

  const deleteManager = async (id) => {
    try {
      await api.delete(`/users/managers/${id}`);
      setManagers((current) => current.filter((entry) => entry.id !== id));
      setApiMessage('Gestor eliminado com sucesso.');
    } catch (error) {
      setApiMessage(error.response?.data?.message || 'Não foi possível eliminar o gestor.');
    }
  };


  const resolveTicket = async (id) => {
    try {
      const response = await api.put(`/tickets/${id}/status`, { estado: 'Resolvido' });
      setTickets((current) => current.map((entry) => (entry.id === id ? response.data.data : entry)));
      setApiMessage('Ticket marcado como resolvido com sucesso.');
    } catch (error) {
      setApiMessage(error.response?.data?.message || 'Nao foi possivel marcar o ticket como resolvido.');
    }
  };
  return (
    <>
      <DetailModal item={selectedItem} title="Detalhes" onClose={() => setSelectedItem(null)} />

      <SimpleDialog show={showAddUserDialog} title="Adicionar Novo Utilizador" description="Preencha os dados do novo utilizador" onClose={() => setShowAddUserDialog(false)}>
        <div className="d-grid gap-3">
          <input className="form-control" placeholder="Nome completo" value={newUserData.name} onChange={(e) => setNewUserData({ ...newUserData, name: e.target.value })} />
          <input className="form-control" placeholder="Nome de utilizador" value={newUserData.username} onChange={(e) => setNewUserData({ ...newUserData, username: e.target.value })} />
          <input type="password" className="form-control" placeholder="Senha" value={newUserData.password} onChange={(e) => setNewUserData({ ...newUserData, password: e.target.value })} />

          <input className="form-control" placeholder="Email" value={newUserData.email} onChange={(e) => setNewUserData({ ...newUserData, email: e.target.value })} />
          <input className="form-control" placeholder="Telefone" value={newUserData.phone} onChange={(e) => setNewUserData({ ...newUserData, phone: e.target.value })} />
          <input className="form-control" placeholder="Departamento" value={newUserData.department} onChange={(e) => setNewUserData({ ...newUserData, department: e.target.value })} />
          <select className="form-select" value={newUserData.managerId} onChange={(e) => setNewUserData({ ...newUserData, managerId: e.target.value })}>
            <option value="">Gestor associado (opcional)</option>
            {managers.map((mgr) => (
              <option key={mgr.id} value={mgr.id}>{mgr.name} ({mgr.username})</option>
            ))}
          </select>
          <div className="d-flex gap-2 justify-content-end">
            <button className="btn btn-outline-secondary" onClick={() => setShowAddUserDialog(false)}>Cancelar</button>
            <button className="btn btn-primary" onClick={addUser}>Adicionar</button>
          </div>
        </div>
      </SimpleDialog>

      <SimpleDialog show={showAddManagerDialog} title="Adicionar Novo Gestor" description="Preencha os dados do novo gestor" onClose={() => setShowAddManagerDialog(false)}>
        <div className="d-grid gap-3">
          <input className="form-control" placeholder="Nome completo" value={newManagerData.name} onChange={(e) => setNewManagerData({ ...newManagerData, name: e.target.value })} />
          <input className="form-control" placeholder="Nome de utilizador" value={newManagerData.username} onChange={(e) => setNewManagerData({ ...newManagerData, username: e.target.value })} />
          <input type="password" className="form-control" placeholder="Senha" value={newManagerData.password} onChange={(e) => setNewManagerData({ ...newManagerData, password: e.target.value })} />
          <input className="form-control" placeholder="Email" value={newManagerData.email} onChange={(e) => setNewManagerData({ ...newManagerData, email: e.target.value })} />
          <input className="form-control" placeholder="Telefone" value={newManagerData.phone} onChange={(e) => setNewManagerData({ ...newManagerData, phone: e.target.value })} />
          <input className="form-control" placeholder="Departamento" value={newManagerData.department} onChange={(e) => setNewManagerData({ ...newManagerData, department: e.target.value })} />
          <input className="form-control" placeholder="Tamanho da equipa" value={newManagerData.teamSize} onChange={(e) => setNewManagerData({ ...newManagerData, teamSize: e.target.value })} />
          <div className="d-flex gap-2 justify-content-end">
            <button className="btn btn-outline-secondary" onClick={() => setShowAddManagerDialog(false)}>Cancelar</button>
            <button className="btn btn-primary" onClick={addManager}>Adicionar</button>
          </div>
        </div>
      </SimpleDialog>

      <SimpleDialog show={show2FADialog} title="Autenticação de Dois Fatores" description="Configure a autenticação de dois fatores" onClose={() => setShow2FADialog(false)}>
        <div className="d-grid gap-3">
          <label className="settings-inline"><span>Ativar 2FA</span><input type="checkbox" checked={twoFAConfig.enabled} onChange={(e) => setTwoFAConfig({ ...twoFAConfig, enabled: e.target.checked })} /></label>
          <select className="form-select" value={twoFAConfig.method} onChange={(e) => setTwoFAConfig({ ...twoFAConfig, method: e.target.value })}>
            <option>Aplicação autenticadora</option>
            <option>SMS</option>
            <option>Email</option>
          </select>
        </div>
      </SimpleDialog>

      <SimpleDialog show={showPasswordDialog} title="Política de Senhas" description="Defina os requisitos de palavra-passe" onClose={() => setShowPasswordDialog(false)}>
        <div className="d-grid gap-3">
          <input className="form-control" value={passwordConfig.minLength} onChange={(e) => setPasswordConfig({ ...passwordConfig, minLength: e.target.value })} placeholder="Comprimento mínimo" />
          <label className="settings-inline"><span>Requer letras maiúsculas</span><input type="checkbox" checked={passwordConfig.requireUppercase} onChange={(e) => setPasswordConfig({ ...passwordConfig, requireUppercase: e.target.checked })} /></label>
          <label className="settings-inline"><span>Requer números</span><input type="checkbox" checked={passwordConfig.requireNumbers} onChange={(e) => setPasswordConfig({ ...passwordConfig, requireNumbers: e.target.checked })} /></label>
          <input className="form-control" value={passwordConfig.expirationDays} onChange={(e) => setPasswordConfig({ ...passwordConfig, expirationDays: e.target.value })} placeholder="Expiração em dias" />
        </div>
      </SimpleDialog>

      <SimpleDialog show={showBackupDialog} title="Backup Automático" description="Configure a frequência de backup" onClose={() => setShowBackupDialog(false)}>
        <div className="d-grid gap-3">
          <select className="form-select" value={backupConfig.frequency} onChange={(e) => setBackupConfig({ ...backupConfig, frequency: e.target.value })}>
            <option>Diário</option>
            <option>Semanal</option>
            <option>Mensal</option>
          </select>
          <input className="form-control" value={backupConfig.time} onChange={(e) => setBackupConfig({ ...backupConfig, time: e.target.value })} placeholder="Hora" />
          <input className="form-control" value={backupConfig.retention} onChange={(e) => setBackupConfig({ ...backupConfig, retention: e.target.value })} placeholder="Retenção em dias" />
        </div>
      </SimpleDialog>

      <SimpleDialog show={showNotificationsDialog} title="Notificações de Segurança" description="Gerir canais de notificação" onClose={() => setShowNotificationsDialog(false)}>
        <div className="d-grid gap-3">
          <label className="settings-inline"><span>Email</span><input type="checkbox" checked={notificationConfig.email} onChange={(e) => setNotificationConfig({ ...notificationConfig, email: e.target.checked })} /></label>
          <label className="settings-inline"><span>SMS</span><input type="checkbox" checked={notificationConfig.sms} onChange={(e) => setNotificationConfig({ ...notificationConfig, sms: e.target.checked })} /></label>
          <label className="settings-inline"><span>Push</span><input type="checkbox" checked={notificationConfig.push} onChange={(e) => setNotificationConfig({ ...notificationConfig, push: e.target.checked })} /></label>
        </div>
      </SimpleDialog>

      <DashboardLayout
        user={user}
        title="Dashboard do Administrador"
        subtitle="Visão geral do sistema de segurança"
        menuItems={menuItems}
        activeMenu={activeMenu}
        onSelectMenu={setActiveMenu}
        onLogout={onLogout}
        alertCount={alerts.length}
      >
        {apiMessage ? <div className="alert alert-info py-2">{apiMessage}</div> : null}

        {activeMenu === 'dashboard' ? (
          <>
            <div className="row g-4 mb-4">
              {stats.map((stat) => (
                <div className="col-md-6 col-xl-3" key={stat.title}>
                  <div className="card shadow-sm border-0 h-100">
                    <div className="card-body">
                      <div className="text-muted small mb-2">{stat.title}</div>
                      <div className="fs-3 fw-semibold">{stat.value}</div>
                      <div className={`small mt-2 ${stat.tone}`}>{stat.change} vs semana passada</div>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="card shadow-sm border-0 mb-4">
              <div className="card-body">
                <h3 className="h5 mb-1">Alertas Recentes</h3>
                <p className="text-muted small mb-4">Atividade de segurança em tempo real</p>
                <div className="d-grid gap-3">
                  {alerts.map((alert) => (
                    <div className="alert-row" key={alert.id}>
                      <span className={`alert-dot ${alert.type === 'Crítico' ? 'critical' : alert.type === 'Aviso' ? 'warning' : 'info'}`}></span>
                      <div className="flex-grow-1">
                        <div>{alert.message}</div>
                        <div className="small text-muted mt-1">{alert.source} • {alert.time}</div>
                      </div>
                      <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(alert)}>Investigar</button>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="card shadow-sm border-0">
              <div className="card-body">
                <h3 className="h5 mb-3">Nova Empresa</h3>
                <form className="row g-2 mb-4" onSubmit={submitEmpresa}>
                  <div className="col-md-5"><input className="form-control" placeholder="Nome da empresa" value={form.nome} onChange={(e) => setForm({ ...form, nome: e.target.value })} /></div>
                  <div className="col-md-5"><input className="form-control" placeholder="NIF (9 dígitos)" maxLength={9} value={form.nif} onChange={(e) => setForm({ ...form, nif: e.target.value.replace(/\D/g, '').slice(0, 9) })} /></div>
                  <div className="col-md-2 d-grid"><button className="btn btn-success" type="submit">Guardar</button></div>
                </form>
                <h4 className="h6 mb-3">Empresas Registadas</h4>
                {loading ? <p className="mb-0">A carregar...</p> : (
                  <ul className="list-group">
                    {empresas.map((empresa) => (
                      <li key={empresa.id_empresa} className="list-group-item d-flex justify-content-between">
                        <span>{empresa.nome}</span>
                        <span className="text-muted">{empresa.nif}</span>
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </div>
          </>
        ) : null}

        {activeMenu === 'monitoring' ? (
          <div>
            {/* Header com auto-refresh */}
            <div className="d-flex justify-content-between align-items-center mb-4">
              <div>
                <h3 className="h5 mb-1">Monitorização do Sistema</h3>
                <p className="text-muted small mb-0">
                  {monitoringData
                    ? `Última atualização: ${new Date().toLocaleTimeString('pt-PT')}`
                    : 'A carregar...'}
                </p>
              </div>
              <div className="d-flex gap-2 align-items-center">
                <div className="form-check form-switch mb-0 me-2">
                  <input
                    className="form-check-input"
                    type="checkbox"
                    id="autoRefreshToggle"
                    checked={autoRefresh}
                    onChange={(e) => setAutoRefresh(e.target.checked)}
                  />
                  <label className="form-check-label small" htmlFor="autoRefreshToggle">
                    Auto-refresh (30s)
                  </label>
                </div>
                <button
                  className="btn btn-sm btn-outline-secondary"
                  onClick={() => { setMonitoringLoading(true); api.get('/monitoring/status').then(r => setMonitoringData(r.data.data)).catch(() => {}).finally(() => setMonitoringLoading(false)); }}
                  disabled={monitoringLoading}
                >
                  {monitoringLoading ? '...' : '↻ Atualizar'}
                </button>
              </div>
            </div>

            {monitoringError ? (
              <div className="alert alert-danger">{monitoringError}</div>
            ) : monitoringLoading && !monitoringData ? (
              <div className="text-center py-5 text-muted">A carregar dados de monitorização...</div>
            ) : monitoringData ? (
              <>
                {/* KPI Cards */}
                <div className="row g-3 mb-4">
                  {[
                    {
                      title: 'Utilizadores Online',
                      value: `${monitoringData.utilizadores.online}/${monitoringData.utilizadores.total}`,
                      sub: `${monitoringData.utilizadores.gestoresOnline}/${monitoringData.utilizadores.gestoresTotal} gestores online`,
                      color: 'text-success',
                    },
                    {
                      title: 'Tickets Abertos',
                      value: monitoringData.tickets.abertos,
                      sub: `${monitoringData.tickets.emCurso} em curso · ${monitoringData.tickets.fechados} fechados`,
                      color: monitoringData.tickets.abertos > 10 ? 'text-danger' : 'text-warning',
                    },
                    {
                      title: 'Eventos Hoje',
                      value: monitoringData.logs.eventosHoje,
                      sub: `${monitoringData.logs.loginsSuccessHoje} logins · ${monitoringData.logs.loginsFalhadosHoje} falhados`,
                      color: monitoringData.logs.loginsFalhadosHoje > 5 ? 'text-danger' : 'text-success',
                    },
                    {
                      title: 'Taxa de Resolução',
                      value: `${monitoringData.tickets.taxaResolucao}%`,
                      sub: `${monitoringData.tickets.total} tickets no total`,
                      color: monitoringData.tickets.taxaResolucao >= 70 ? 'text-success' : 'text-warning',
                    },
                  ].map(({ title, value, sub, color }) => (
                    <div className="col-md-6 col-xl-3" key={title}>
                      <div className="card shadow-sm border-0 h-100">
                        <div className="card-body">
                          <div className="text-muted small mb-2">{title}</div>
                          <div className={`fs-3 fw-semibold ${color}`}>{value}</div>
                          <div className="small text-muted mt-2">{sub}</div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="row g-3">
                  {/* Estado dos Serviços */}
                  <div className="col-lg-4">
                    <div className="card shadow-sm border-0 h-100">
                      <div className="card-body">
                        <h6 className="fw-semibold mb-3">Estado dos Serviços</h6>
                        <div className="d-grid gap-2">
                          {monitoringData.servicos.map((s) => (
                            <div key={s.nome} className="d-flex justify-content-between align-items-center py-2 border-bottom">
                              <div>
                                <div className="fw-medium small">{s.nome}</div>
                                <div className="text-muted" style={{ fontSize: '0.75rem' }}>{s.descricao}</div>
                              </div>
                              <span className={`badge ${s.estado === 'online' ? 'text-bg-success' : s.estado === 'degradado' ? 'text-bg-warning' : 'text-bg-danger'}`}>
                                {s.estado === 'online' ? 'Online' : s.estado === 'degradado' ? 'Degradado' : 'Offline'}
                              </span>
                            </div>
                          ))}
                        </div>
                        <div className="mt-3 d-flex align-items-center gap-2">
                          <span className="badge text-bg-success rounded-pill" style={{ width: 10, height: 10, padding: 0 }}>&nbsp;</span>
                          <span className="small text-muted">Todos os serviços operacionais</span>
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Eventos Recentes */}
                  <div className="col-lg-8">
                    <div className="card shadow-sm border-0 h-100">
                      <div className="card-body">
                        <h6 className="fw-semibold mb-3">Eventos Recentes</h6>
                        {monitoringData.ultimosEventos.length === 0 ? (
                          <p className="text-muted small">Sem eventos registados.</p>
                        ) : (
                          <div className="table-responsive">
                            <table className="table table-sm align-middle mb-0">
                              <thead className="table-light">
                                <tr>
                                  <th style={{ width: 130 }}>Hora</th>
                                  <th style={{ width: 60 }}>Origem</th>
                                  <th>Evento</th>
                                  <th style={{ width: 80 }}>Nível</th>
                                </tr>
                              </thead>
                              <tbody>
                                {monitoringData.ultimosEventos.map((ev) => {
                                  const nivelBadge = ev.nivel === 'Info'
                                    ? 'text-bg-success'
                                    : ev.nivel === 'Aviso'
                                    ? 'text-bg-warning'
                                    : 'text-bg-danger';
                                  return (
                                    <tr key={ev.id_log}>
                                      <td className="text-muted small text-nowrap">
                                        {new Date(ev.created_at).toLocaleTimeString('pt-PT')}
                                      </td>
                                      <td>
                                        <span className="badge text-bg-secondary">{ev.origem}</span>
                                      </td>
                                      <td className="small">{ev.evento}</td>
                                      <td>
                                        <span className={`badge ${nivelBadge}`}>{ev.nivel}</span>
                                      </td>
                                    </tr>
                                  );
                                })}
                              </tbody>
                            </table>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              </>
            ) : null}
          </div>
        ) : null}


         {activeMenu === 'tickets' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <h3 className="h5 mb-1">Tickets dos Clientes</h3>
              <p className="text-muted small mb-4">Todos os tickets abertos no sistema</p>
              <div className="d-grid gap-3">
                {tickets.map((ticket) => (
                  <div className="admin-list-row" key={ticket.id}>
                    <div className="flex-grow-1">
                      <div className="fw-medium">#{ticket.id} - {ticket.title}</div>
                      <div className="small text-muted">Cliente: {ticket.requester || 'N/A'} | Prioridade: {ticket.priority}</div>
                    </div>
                    <span className="badge text-bg-secondary">{ticket.status}</span>
                    <div className="d-flex gap-2">
                      <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(ticket)}>Ver Detalhes</button>
                      {ticket.status !== 'Resolvido' ? (
                        <button className="btn btn-sm btn-outline-success" onClick={() => resolveTicket(ticket.id)}>Marcar Resolvido</button>
                      ) : null}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}
        {activeMenu === 'stats' ? (
          <div>
            <div className="d-flex justify-content-between align-items-center mb-4">
              <h3 className="h5 mb-0">Estatísticas do Sistema</h3>
              <button
                className="btn btn-sm btn-outline-secondary"
                disabled={statsLoading}
                onClick={() => { setStatsLoading(true); api.get('/stats/summary').then(r => setStatsData(r.data.data)).catch(() => {}).finally(() => setStatsLoading(false)); }}
              >
                {statsLoading ? '...' : '↻ Atualizar'}
              </button>
            </div>

            {statsLoading && !statsData ? (
              <div className="text-center py-5 text-muted">A calcular estatísticas...</div>
            ) : statsData ? (() => {
              const totalTickets = statsData.ticketsPorEstado.reduce((s, r) => s + r.count, 0);
              const totalPrioridade = statsData.ticketsPorPrioridade.reduce((s, r) => s + r.count, 0);
              const totalUsers = statsData.utilizadoresPorClasse.reduce((s, r) => s + r.count, 0);
              const maxTicketDia = Math.max(1, ...statsData.ticketsPorDia.map(r => r.total));
              const maxLogDia = Math.max(1, ...statsData.logsPorDia.map(r => r.total));

              const estadoCores = { 'Aberto': 'bg-danger', 'Em Curso': 'bg-warning', 'Fechado': 'bg-success' };
              const prioridadeCores = { 'Baixa': 'bg-success', 'Média': 'bg-info', 'Alta': 'bg-warning', 'Crítica': 'bg-danger' };
              const classeCores = { admin: 'bg-primary', manager: 'bg-info', user: 'bg-secondary' };
              const classeLabels = { admin: 'Administradores', manager: 'Gestores', user: 'Utilizadores' };

              return (
                <>
                  {/* KPI Cards */}
                  <div className="row g-3 mb-4">
                    {[
                      { label: 'Total Utilizadores', value: statsData.kpis.totalUsers, sub: 'na plataforma', color: 'text-primary' },
                      { label: 'Taxa de Resolução', value: `${statsData.kpis.taxaResolucao}%`, sub: 'tickets fechados', color: statsData.kpis.taxaResolucao >= 70 ? 'text-success' : 'text-warning' },
                      { label: 'MTTR Médio', value: statsData.kpis.mttr || '—', sub: 'tempo de resolução', color: 'text-info' },
                      { label: 'Falhas de Login Hoje', value: `${statsData.kpis.taxaFalhasLogin}%`, sub: `${statsData.kpis.loginsFalhadosHoje} de ${statsData.kpis.loginsHoje + statsData.kpis.loginsFalhadosHoje} tentativas`, color: statsData.kpis.taxaFalhasLogin > 20 ? 'text-danger' : 'text-success' },
                    ].map(({ label, value, sub, color }) => (
                      <div className="col-md-6 col-xl-3" key={label}>
                        <div className="card shadow-sm border-0 h-100">
                          <div className="card-body">
                            <div className="text-muted small mb-1">{label}</div>
                            <div className={`fs-2 fw-bold ${color}`}>{value}</div>
                            <div className="text-muted small mt-1">{sub}</div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>

                  <div className="row g-3 mb-3">
                    {/* Tickets por Estado */}
                    <div className="col-lg-4">
                      <div className="card shadow-sm border-0 h-100">
                        <div className="card-body">
                          <h6 className="fw-semibold mb-3">Tickets por Estado</h6>
                          {totalTickets === 0 ? <p className="text-muted small">Sem tickets.</p> : (
                            <div className="d-grid gap-3">
                              {statsData.ticketsPorEstado.map(({ estado, count }) => (
                                <div key={estado}>
                                  <div className="d-flex justify-content-between small mb-1">
                                    <span>{estado}</span>
                                    <span className="fw-semibold">{count} <span className="text-muted fw-normal">({Math.round(count / totalTickets * 100)}%)</span></span>
                                  </div>
                                  <div className="progress" style={{ height: 8 }}>
                                    <div className={`progress-bar ${estadoCores[estado] || 'bg-secondary'}`} style={{ width: `${Math.round(count / totalTickets * 100)}%` }} />
                                  </div>
                                </div>
                              ))}
                            </div>
                          )}
                          <div className="text-muted small mt-3">Total: {totalTickets} tickets</div>
                        </div>
                      </div>
                    </div>

                    {/* Tickets por Prioridade */}
                    <div className="col-lg-4">
                      <div className="card shadow-sm border-0 h-100">
                        <div className="card-body">
                          <h6 className="fw-semibold mb-3">Tickets por Prioridade</h6>
                          {totalPrioridade === 0 ? <p className="text-muted small">Sem tickets.</p> : (
                            <div className="d-grid gap-3">
                              {['Crítica', 'Alta', 'Média', 'Baixa'].map((pri) => {
                                const item = statsData.ticketsPorPrioridade.find(r => r.prioridade === pri);
                                const count = item?.count || 0;
                                return (
                                  <div key={pri}>
                                    <div className="d-flex justify-content-between small mb-1">
                                      <span>{pri}</span>
                                      <span className="fw-semibold">{count} <span className="text-muted fw-normal">({Math.round(count / totalPrioridade * 100)}%)</span></span>
                                    </div>
                                    <div className="progress" style={{ height: 8 }}>
                                      <div className={`progress-bar ${prioridadeCores[pri] || 'bg-secondary'}`} style={{ width: `${Math.round(count / totalPrioridade * 100)}%` }} />
                                    </div>
                                  </div>
                                );
                              })}
                            </div>
                          )}
                        </div>
                      </div>
                    </div>

                    {/* Utilizadores por Tipo */}
                    <div className="col-lg-4">
                      <div className="card shadow-sm border-0 h-100">
                        <div className="card-body">
                          <h6 className="fw-semibold mb-3">Utilizadores por Tipo</h6>
                          {totalUsers === 0 ? <p className="text-muted small">Sem utilizadores.</p> : (
                            <div className="d-grid gap-3">
                              {statsData.utilizadoresPorClasse.map(({ classe, count }) => (
                                <div key={classe}>
                                  <div className="d-flex justify-content-between small mb-1">
                                    <span>{classeLabels[classe] || classe}</span>
                                    <span className="fw-semibold">{count}</span>
                                  </div>
                                  <div className="progress" style={{ height: 8 }}>
                                    <div className={`progress-bar ${classeCores[classe] || 'bg-secondary'}`} style={{ width: `${Math.round(count / totalUsers * 100)}%` }} />
                                  </div>
                                </div>
                              ))}
                            </div>
                          )}
                          {statsData.utilizadoresPorDept.length > 0 && (
                            <>
                              <h6 className="fw-semibold mt-4 mb-2" style={{ fontSize: '0.8rem' }}>Por Departamento</h6>
                              {statsData.utilizadoresPorDept.map(({ departamento, count }) => (
                                <div key={departamento} className="d-flex justify-content-between small py-1 border-bottom">
                                  <span className="text-truncate me-2">{departamento}</span>
                                  <span className="fw-semibold text-nowrap">{count}</span>
                                </div>
                              ))}
                            </>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="row g-3">
                    {/* Tickets últimos 7 dias */}
                    <div className="col-lg-6">
                      <div className="card shadow-sm border-0 h-100">
                        <div className="card-body">
                          <h6 className="fw-semibold mb-3">Tickets criados — últimos 7 dias</h6>
                          {statsData.ticketsPorDia.length === 0 ? (
                            <p className="text-muted small">Sem atividade recente.</p>
                          ) : (
                            <div className="d-grid gap-2">
                              {statsData.ticketsPorDia.map(({ dia, total }) => (
                                <div key={dia} className="d-flex align-items-center gap-2">
                                  <span className="text-muted small" style={{ width: 42, flexShrink: 0 }}>{dia}</span>
                                  <div className="flex-grow-1 bg-light rounded" style={{ height: 20 }}>
                                    <div
                                      className="bg-primary rounded"
                                      style={{ height: 20, width: `${Math.round(total / maxTicketDia * 100)}%`, minWidth: total > 0 ? 4 : 0, transition: 'width .3s' }}
                                    />
                                  </div>
                                  <span className="fw-semibold small" style={{ width: 24, flexShrink: 0 }}>{total}</span>
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      </div>
                    </div>

                    {/* Atividade de login últimos 7 dias */}
                    <div className="col-lg-6">
                      <div className="card shadow-sm border-0 h-100">
                        <div className="card-body">
                          <h6 className="fw-semibold mb-3">Atividade de login — últimos 7 dias</h6>
                          {statsData.logsPorDia.length === 0 ? (
                            <p className="text-muted small">Sem atividade recente.</p>
                          ) : (
                            <div className="d-grid gap-2">
                              {statsData.logsPorDia.map(({ dia, loginsOk, loginsFail }) => {
                                const tot = loginsOk + loginsFail || 1;
                                return (
                                  <div key={dia} className="d-flex align-items-center gap-2">
                                    <span className="text-muted small" style={{ width: 42, flexShrink: 0 }}>{dia}</span>
                                    <div className="flex-grow-1 bg-light rounded overflow-hidden" style={{ height: 20 }}>
                                      <div className="d-flex h-100" style={{ width: `${Math.round((loginsOk + loginsFail) / maxLogDia * 100)}%` }}>
                                        <div className="bg-success" style={{ width: `${Math.round(loginsOk / tot * 100)}%` }} />
                                        <div className="bg-danger" style={{ width: `${Math.round(loginsFail / tot * 100)}%` }} />
                                      </div>
                                    </div>
                                    <span className="small text-nowrap" style={{ width: 60, flexShrink: 0 }}>
                                      <span className="text-success">{loginsOk}</span>
                                      <span className="text-muted"> / </span>
                                      <span className="text-danger">{loginsFail}</span>
                                    </span>
                                  </div>
                                );
                              })}
                              <div className="d-flex gap-3 mt-1">
                                <span className="small"><span className="text-success fw-semibold">■</span> Sucesso</span>
                                <span className="small"><span className="text-danger fw-semibold">■</span> Falhado</span>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                </>
              );
            })() : <div className="text-center py-5 text-muted">Sem dados disponíveis.</div>}
          </div>
        ) : null}

        {activeMenu === 'users' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <div>
                  <h3 className="h5 mb-1">Todos os Utilizadores</h3>
                  <p className="text-muted small mb-0">Utilizadores ativos no sistema</p>
                </div>
                <button className="btn btn-primary" onClick={() => setShowAddUserDialog(true)}>Adicionar Utilizador</button>
              </div>
              <div className="d-grid gap-3">
                {users.map((item) => (
                  <div className="admin-list-row" key={item.id}>
                    <div className="list-avatar user">{item.name.charAt(0)}</div>
                    <div className="flex-grow-1">
                      <div className="fw-medium">{item.name}</div>
                      <div className="small text-muted">{item.email}</div>
                      <div className="small text-muted">Utilizador: {item.username}</div>
                      {item.managerId ? (
                        <div className="small text-muted">Gestor: {managers.find((mgr) => mgr.id === item.managerId)?.name || 'ID ' + item.managerId}</div>
                      ) : null}
                    </div>
                    <span className="badge text-bg-secondary">{item.role}</span>
                    <div className="small text-muted">{item.lastActive}</div>
                    <div className="d-flex gap-2">
                      <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(item)}>Ver Detalhes</button>
                      <button className="btn btn-sm btn-outline-danger" onClick={() => deleteUser(item.id)}>Eliminar</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'managers' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <div>
                  <h3 className="h5 mb-1">Todos os Gestores</h3>
                  <p className="text-muted small mb-0">Gestores ativos e as suas equipas</p>
                </div>
                <button className="btn btn-primary" onClick={() => setShowAddManagerDialog(true)}>Adicionar Gestor</button>
              </div>
              <div className="d-grid gap-3">
                {managers.map((item) => (
                  <div className="admin-list-row" key={item.id}>
                    <div className="list-avatar manager">{item.name.charAt(0)}</div>
                    <div className="flex-grow-1">
                      <div className="fw-medium">{item.name}</div>
                      <div className="small text-muted">{item.email}</div>
                      <div className="small text-muted">Utilizador: {item.username}</div>
                      <div className="small text-muted">Departamento: {item.username}</div>
                    </div>
                    <div className="text-center small"><div className="text-muted">Equipa</div><div className="fw-semibold">{item.team}</div></div>
                    <div className="text-center small"><div className="text-muted">Resolvidos</div><div className="fw-semibold">{item.incidentsResolved}</div></div>
                    <div className="text-center small"><div className="text-muted">Performance</div><div className="fw-semibold text-success">{item.performance}%</div></div>
                    <div className="d-flex gap-2">
                      <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(item)}>Ver Detalhes</button>
                      <button className="btn btn-sm btn-outline-danger" onClick={() => deleteManager(item.id)}>Eliminar</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'alerts' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <h3 className="h5 mb-1">Todos os Alertas</h3>
              <p className="text-muted small mb-4">Histórico completo de alertas de segurança</p>
              <div className="d-grid gap-3">
                {alerts.map((alert) => (
                  <div className="alert-row" key={alert.id}>
                    <span className={`alert-dot ${alert.type === 'Crítico' ? 'critical' : alert.type === 'Aviso' ? 'warning' : 'info'}`}></span>
                    <div className="flex-grow-1">
                      <div>{alert.message}</div>
                      <div className="small text-muted mt-1">{alert.source} • {alert.time}</div>
                    </div>
                    <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(alert)}>Investigar</button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'logs' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center mb-3">
                <h3 className="h5 mb-0">Logs de Autenticação e Registo</h3>
                <div className="d-flex gap-2">
                  {[
                    { value: 'todos', label: 'Todos' },
                    { value: 'login', label: 'Login' },
                    { value: 'user', label: 'Registo' },
                    { value: 'manager', label: 'Gestores' },
                  ].map(({ value, label }) => (
                    <button
                      key={value}
                      className={`btn btn-sm ${logsFilter === value ? 'btn-primary' : 'btn-outline-secondary'}`}
                      onClick={() => setLogsFilter(value)}
                    >
                      {label}
                    </button>
                  ))}
                  <button
                    className="btn btn-sm btn-outline-secondary"
                    onClick={() => setLogsFilter(logsFilter)}
                    title="Atualizar"
                  >
                    &#x21bb;
                  </button>
                </div>
              </div>
              {logsLoading ? (
                <div className="text-center py-4 text-muted">A carregar logs...</div>
              ) : logs.length === 0 ? (
                <div className="text-center py-4 text-muted">Sem logs para este filtro.</div>
              ) : (
                <div className="table-responsive">
                  <table className="table align-middle table-hover">
                    <thead className="table-light">
                      <tr>
                        <th>Data/Hora</th>
                        <th>Origem</th>
                        <th>Utilizador</th>
                        <th>Evento</th>
                        <th>Nível</th>
                      </tr>
                    </thead>
                    <tbody>
                      {logs.map((log) => {
                        const nivelBadge = log.nivel === 'Info'
                          ? 'text-bg-success'
                          : log.nivel === 'Aviso'
                          ? 'text-bg-warning'
                          : 'text-bg-danger';
                        const dt = new Date(log.created_at);
                        const dateStr = dt.toLocaleDateString('pt-PT');
                        const timeStr = dt.toLocaleTimeString('pt-PT');
                        return (
                          <tr key={log.id_log}>
                            <td className="text-nowrap small">
                              <div>{dateStr}</div>
                              <div className="text-muted">{timeStr}</div>
                            </td>
                            <td><span className="badge text-bg-secondary">{log.origem}</span></td>
                            <td className="small">{log.actor_username || '—'}</td>
                            <td>{log.evento}</td>
                            <td><span className={`badge ${nivelBadge}`}>{log.nivel}</span></td>
                          </tr>
                        );
                      })}
                          </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        ) : null}

        {activeMenu === 'reports' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <div>
                  <h3 className="h5 mb-1">Relatórios</h3>
                  <p className="text-muted small mb-0">Exportação de dados operacionais em CSV e relatório executivo imprimível</p>
                </div>
              </div>
              <div className="d-grid gap-3">
                {[
                  {
                    tipo: 'executivo',
                    nome: 'Relatório Executivo',
                    descricao: 'Sumário consolidado de utilizadores, tickets e autenticação',
                    badge: 'HTML',
                    badgeColor: 'text-bg-primary',
                    btnLabel: 'Abrir',
                  },
                  {
                    tipo: 'utilizadores',
                    nome: 'Utilizadores',
                    descricao: 'Lista completa de utilizadores com estado e tickets',
                    badge: 'CSV',
                    badgeColor: 'text-bg-success',
                    btnLabel: 'Exportar',
                  },
                  {
                    tipo: 'gestores',
                    nome: 'Gestores',
                    descricao: 'Lista de gestores com departamento e dimensão de equipa',
                    badge: 'CSV',
                    badgeColor: 'text-bg-success',
                    btnLabel: 'Exportar',
                  },
                  {
                    tipo: 'tickets',
                    nome: 'Tickets de Suporte',
                    descricao: 'Histórico de tickets com prioridade, estado e responsável',
                    badge: 'CSV',
                    badgeColor: 'text-bg-success',
                    btnLabel: 'Exportar',
                  },
                  {
                    tipo: 'logs',
                    nome: 'Logs de Autenticação',
                    descricao: 'Histórico de logins e registos (últimos 500 eventos)',
                    badge: 'CSV',
                    badgeColor: 'text-bg-success',
                    btnLabel: 'Exportar',
                  },
                ].map(({ tipo, nome, descricao, badge, badgeColor, btnLabel }) => (
                  <div className="settings-row" key={tipo}>
                    <div>
                      <div className="fw-medium">{nome}</div>
                      <div className="small text-muted">{descricao}</div>
                    </div>
                    <div className="d-flex gap-2 align-items-center">
                      <span className={`badge ${badgeColor}`}>{badge}</span>
                      <button
                        className="btn btn-outline-primary btn-sm"
                        disabled={reportLoading === tipo}
                        onClick={() => handleExportReport(tipo)}
                      >
                        {reportLoading === tipo ? 'A gerar...' : btnLabel}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'chat' ? <AdminChatSection user={user} managers={managers} /> : null}

        {activeMenu === 'homepage' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <h3 className="h5 mb-1">Editar Página Principal</h3>
              <p className="text-muted small mb-4">Altera o título e o texto introdutório que aparecem na primeira página.</p>
              <div className="mb-3">
                <label className="form-label fw-medium">Título</label>
                <input className="form-control" value={hpTitle} onChange={(e) => { setHpTitle(e.target.value); setHpSaved(false); }} />
              </div>
              <div className="mb-4">
                <label className="form-label fw-medium">Descrição</label>
                <textarea className="form-control" rows={5} value={hpDesc} onChange={(e) => { setHpDesc(e.target.value); setHpSaved(false); }} />
              </div>
              <div className="d-flex align-items-center gap-3">
                <button className="btn btn-success" onClick={() => { localStorage.setItem('hp_title', hpTitle); localStorage.setItem('hp_desc', hpDesc); setHpSaved(true); }}>Guardar</button>
                <button className="btn btn-outline-secondary" onClick={() => { setHpTitle(HOMEPAGE_DEFAULTS.title); setHpDesc(HOMEPAGE_DEFAULTS.description); setHpSaved(false); }}>Repor texto original</button>
                {hpSaved && <span className="text-success small">Guardado com sucesso.</span>}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'settings' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <h3 className="h5 mb-4">Configurações do Sistema</h3>
              <div className="d-grid gap-3">
                {[
                  ['Autenticação de Dois Fatores', () => setShow2FADialog(true)],
                  ['Política de Senhas', () => setShowPasswordDialog(true)],
                  ['Backup Automático', () => setShowBackupDialog(true)],
                  ['Notificações de Segurança', () => setShowNotificationsDialog(true)],
                ].map(([label, action]) => (
                  <div className="settings-row" key={label}>
                    <div>
                      <div className="fw-medium">{label}</div>
                      <div className="small text-muted">Configurar parâmetros de segurança</div>
                    </div>
                    <button className="btn btn-outline-secondary" onClick={action}>Configurar</button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}
      </DashboardLayout>
    </>
  );
}

function ManagerDashboard({ user, onLogout }) {
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [selectedItem, setSelectedItem] = useState(null);
  const [showAddUserDialog, setShowAddUserDialog] = useState(false);
  const [showNewIncidentDialog, setShowNewIncidentDialog] = useState(false);
  const [showManageUserDialog, setShowManageUserDialog] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [newUserData, setNewUserData] = useState({ name: '', username: '', password: '', email: '', phone: '', department: '' });
  const [newIncidentData, setNewIncidentData] = useState({ title: '', severity: 'Média', assignee: '' });
  const [manageData, setManageData] = useState({ status: 'Online', department: '', role: 'Utilizador' });
  const [alerts] = useState([
    { id: 1, type: 'Crítico', message: 'Tentativa de acesso não autorizado detectada', time: '2 min atrás', source: 'Sistema' },
    { id: 2, type: 'Aviso', message: 'Tráfego anómalo detectado na rede interna', time: '20 min atrás', source: 'Firewall' },
    { id: 3, type: 'Informação', message: 'Novo utilizador adicionado ao sistema', time: '1 hora atrás', source: 'Gestor' },
  ]);
  const [teamMembers] = useState([
    { id: 1, name: 'Carlos Mendes', role: 'Analista de Segurança', email: 'carlos@empresa.com', performance: 95, tasksCompleted: 42, tasksActive: 3, status: 'Online' },
    { id: 2, name: 'Sofia Alves', role: 'Especialista em Redes', email: 'sofia@empresa.com', performance: 92, tasksCompleted: 38, tasksActive: 2, status: 'Online' },
    { id: 3, name: 'Beatriz Lima', role: 'Analista de Vulnerabilidades', email: 'beatriz@empresa.com', performance: 94, tasksCompleted: 40, tasksActive: 2, status: 'Online' },
  ]);
  const [usersList, setUsersList] = useState([]);
  const [incidentsList, setIncidentsList] = useState([]);
  const [managerReportLoading, setManagerReportLoading] = useState(null);

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard' },
    { id: 'team', label: 'Minha Equipa' },
    { id: 'users', label: 'Clientes' },
    { id: 'incidents', label: 'Incidentes' },
    { id: 'alerts', label: 'Alertas' },
    { id: 'reports', label: 'Relatórios' },
    { id: 'chat', label: 'Chat' },
  ];

  useEffect(() => {
    const loadManagerData = async () => {
      try {
        const [usersResponse, ticketsResponse] = await Promise.all([
          api.get(`/users?managerId=${user.id}`),
          api.get('/tickets'),
        ]);
        setUsersList(usersResponse.data.data || []);
        setIncidentsList(ticketsResponse.data.data || []);
      } catch (error) {
        console.error(error);
      }
    };

    loadManagerData();
  }, [user.id]);

  const addUser = async () => {
    if (!newUserData.name.trim() || !newUserData.username.trim() || !newUserData.password.trim()) return;
    try {
      const response = await api.post('/users', {
        nome: newUserData.name.trim(),
        username: newUserData.username.trim(),
        password: newUserData.password.trim(),
        email: newUserData.email.trim(),
        telefone: newUserData.phone.trim(),
        departamento: newUserData.department.trim(),
        managerId: user.id,
      });

      setUsersList((current) => [response.data.data, ...current]);
      setNewUserData({ name: '', username: '', password: '', email: '', phone: '', department: '' });
      setShowAddUserDialog(false);
    } catch (error) {
      console.error(error);
    }
  };

  const addIncident = () => {
    if (!newIncidentData.title.trim()) return;
    setIncidentsList((current) => [
      ...current,
      {
        id: current.length + 1,
        title: newIncidentData.title.trim(),
        severity: newIncidentData.severity,
        status: 'Pendente',
        assignee: newIncidentData.assignee || 'Não atribuído',
        date: new Date().toLocaleDateString('pt-PT'),
      },
    ]);
    setNewIncidentData({ title: '', severity: 'Média', assignee: '' });
    setShowNewIncidentDialog(false);
  };

  const openManageUser = (item) => {
    setSelectedUser(item);
    setManageData({ status: item.status, department: item.department, role: item.role });
    setShowManageUserDialog(true);
  };

  const saveManagedUser = () => {
    setUsersList((current) => current.map((entry) => (
      entry.id === selectedUser.id ? { ...entry, ...manageData } : entry
    )));
    setShowManageUserDialog(false);
    setSelectedUser(null);
  };

  const handleManagerReport = (tipo) => {
    setManagerReportLoading(tipo);
    try {
      const teamIds = new Set(usersList.map((u) => u.id));
      const teamTickets = incidentsList.filter((t) => teamIds.has(t.requesterId));
      const now = new Date();
      const thisMonth = now.getMonth();
      const thisYear = now.getFullYear();

      if (tipo === 'mensal') {
        const ticketsThisMonth = teamTickets.filter((t) => {
          const d = new Date(t.created);
          return d.getMonth() === thisMonth && d.getFullYear() === thisYear;
        });
        const resolved = teamTickets.filter((t) => t.status === 'Fechado' || t.status === 'Resolvido');
        const open = teamTickets.filter((t) => t.status === 'Aberto');

        const rows = usersList.map((u) => {
          const userTickets = teamTickets.filter((t) => t.requesterId === u.id);
          return `<tr><td>${u.name}</td><td>${u.email || '—'}</td><td>${u.department || '—'}</td><td>${userTickets.length}</td></tr>`;
        }).join('');

        const html = `<!DOCTYPE html><html lang="pt"><head><meta charset="UTF-8"/>
<title>Relatório Mensal — ${user.nome}</title>
<style>
  body{font-family:Arial,sans-serif;margin:40px;color:#1a1a2e}
  h1{color:#1b3f9a;border-bottom:3px solid #1b3f9a;padding-bottom:8px}
  h2{color:#1b3f9a;margin-top:28px;font-size:1rem;text-transform:uppercase;letter-spacing:.05em}
  table{width:100%;border-collapse:collapse;margin-top:8px}
  th{background:#1b3f9a;color:#fff;padding:8px 12px;text-align:left}
  td{padding:8px 12px;border-bottom:1px solid #e2e8f0}
  tr:nth-child(even) td{background:#f8fafc}
  .kpi{display:inline-block;background:#f1f5f9;border-left:4px solid #1b3f9a;padding:12px 20px;margin:6px;min-width:130px}
  .kpi-value{font-size:1.8rem;font-weight:700;color:#1b3f9a}
  .kpi-label{font-size:.8rem;color:#64748b;text-transform:uppercase}
  .footer{margin-top:48px;font-size:.8rem;color:#94a3b8;border-top:1px solid #e2e8f0;padding-top:12px}
  @media print{.no-print{display:none}}
</style></head><body>
<div class="no-print" style="margin-bottom:20px">
  <button onclick="window.print()" style="background:#1b3f9a;color:#fff;border:none;padding:10px 24px;border-radius:4px;cursor:pointer">Imprimir / Guardar PDF</button>
</div>
<h1>Relatório Mensal — ${now.toLocaleString('pt-PT', { month: 'long', year: 'numeric' })}</h1>
<p style="color:#64748b">Gestor: <strong>${user.nome}</strong> &nbsp;|&nbsp; Gerado: <strong>${now.toLocaleString('pt-PT')}</strong></p>
<h2>Resumo</h2>
<div>
  <div class="kpi"><div class="kpi-value">${usersList.length}</div><div class="kpi-label">Membros da Equipa</div></div>
  <div class="kpi"><div class="kpi-value">${ticketsThisMonth.length}</div><div class="kpi-label">Tickets este mês</div></div>
  <div class="kpi"><div class="kpi-value">${resolved.length}</div><div class="kpi-label">Resolvidos</div></div>
  <div class="kpi"><div class="kpi-value">${open.length}</div><div class="kpi-label">Em Aberto</div></div>
</div>
<h2>Membros da Equipa</h2>
<table><thead><tr><th>Nome</th><th>Email</th><th>Departamento</th><th>Total Tickets</th></tr></thead>
<tbody>${rows || '<tr><td colspan="4" style="text-align:center;color:#94a3b8">Sem membros</td></tr>'}</tbody></table>
<div class="footer">CyberBoxSecurity — Relatório gerado automaticamente para uso interno.</div>
</body></html>`;
        const w = window.open('', '_blank');
        if (w) { w.document.write(html); w.document.close(); }
        return;
      }

      if (tipo === 'equipa') {
        const rows = usersList.map((u) => {
          const uTickets = teamTickets.filter((t) => t.requesterId === u.id);
          return [u.id, u.name, u.username, u.email || '', u.department || '', u.ticketsOpen, uTickets.length, u.status];
        });
        exportCSV(['ID', 'Nome', 'Username', 'Email', 'Departamento', 'Tickets Abertos', 'Total Tickets', 'Estado'], rows, 'performance_equipa.csv');
        return;
      }

      if (tipo === 'vulnerabilidades') {
        const highPrio = teamTickets.filter((t) => t.priority === 'Alta' || t.priority === 'Crítica');
        const rows = highPrio.map((t) => [t.id, t.title, t.priority, t.status, t.requester || '—', t.created]);
        exportCSV(['ID', 'Título', 'Prioridade', 'Estado', 'Requerente', 'Data'], rows, 'vulnerabilidades.csv');
        return;
      }

      if (tipo === 'resolvidos') {
        const done = teamTickets.filter((t) => t.status === 'Fechado' || t.status === 'Resolvido');
        const rows = done.map((t) => [t.id, t.title, t.priority, t.status, t.requester || '—', t.created, t.updated]);
        exportCSV(['ID', 'Título', 'Prioridade', 'Estado', 'Requerente', 'Criado', 'Resolvido'], rows, 'incidentes_resolvidos.csv');
        return;
      }
    } finally {
      setManagerReportLoading(null);
    }
  };

  return (
    <>
      <DetailModal item={selectedItem} title="Detalhes" onClose={() => setSelectedItem(null)} />
      <SimpleDialog show={showAddUserDialog} title="Adicionar Novo Utilizador" description="Preencha os dados do novo utilizador" onClose={() => setShowAddUserDialog(false)}>
        <div className="d-grid gap-3">
          <input className="form-control" placeholder="Nome completo" value={newUserData.name} onChange={(e) => setNewUserData({ ...newUserData, name: e.target.value })} />
          <input className="form-control" placeholder="Nome de utilizador" value={newUserData.username} onChange={(e) => setNewUserData({ ...newUserData, username: e.target.value })} />
          <input type="password" className="form-control" placeholder="Senha" value={newUserData.password} onChange={(e) => setNewUserData({ ...newUserData, password: e.target.value })} />
          <input className="form-control" placeholder="Email" value={newUserData.email} onChange={(e) => setNewUserData({ ...newUserData, email: e.target.value })} />
          <input className="form-control" placeholder="Telefone" value={newUserData.phone} onChange={(e) => setNewUserData({ ...newUserData, phone: e.target.value })} />
          <input className="form-control" placeholder="Departamento" value={newUserData.department} onChange={(e) => setNewUserData({ ...newUserData, department: e.target.value })} />
          <div className="d-flex gap-2 justify-content-end">
            <button className="btn btn-outline-secondary" onClick={() => setShowAddUserDialog(false)}>Cancelar</button>
            <button className="btn btn-primary" onClick={addUser}>Adicionar</button>
          </div>
        </div>
      </SimpleDialog>

      <SimpleDialog show={showNewIncidentDialog} title="Novo Incidente" description="Registe um novo incidente de segurança" onClose={() => setShowNewIncidentDialog(false)}>
        <div className="d-grid gap-3">
          <input className="form-control" placeholder="Título" value={newIncidentData.title} onChange={(e) => setNewIncidentData({ ...newIncidentData, title: e.target.value })} />
          <select className="form-select" value={newIncidentData.severity} onChange={(e) => setNewIncidentData({ ...newIncidentData, severity: e.target.value })}>
            <option>Baixa</option>
            <option>Média</option>
            <option>Alta</option>
          </select>
          <select className="form-select" value={newIncidentData.assignee} onChange={(e) => setNewIncidentData({ ...newIncidentData, assignee: e.target.value })}>
            <option value="">Selecionar membro...</option>
            {teamMembers.map((member) => <option key={member.id}>{member.name}</option>)}
          </select>
          <div className="d-flex gap-2 justify-content-end">
            <button className="btn btn-outline-secondary" onClick={() => setShowNewIncidentDialog(false)}>Cancelar</button>
            <button className="btn btn-primary" onClick={addIncident}>Criar Incidente</button>
          </div>
        </div>
      </SimpleDialog>

      <SimpleDialog show={showManageUserDialog} title="Gerir Utilizador" description={selectedUser?.name} onClose={() => setShowManageUserDialog(false)}>
        <div className="d-grid gap-3">
          <select className="form-select" value={manageData.status} onChange={(e) => setManageData({ ...manageData, status: e.target.value })}>
            <option>Online</option>
            <option>Offline</option>
          </select>
          <input className="form-control" placeholder="Departamento" value={manageData.department} onChange={(e) => setManageData({ ...manageData, department: e.target.value })} />
          <select className="form-select" value={manageData.role} onChange={(e) => setManageData({ ...manageData, role: e.target.value })}>
            <option>Utilizador</option>
            <option>Gestor</option>
          </select>
          <div className="d-flex gap-2 justify-content-end">
            <button className="btn btn-outline-secondary" onClick={() => setShowManageUserDialog(false)}>Cancelar</button>
            <button className="btn btn-primary" onClick={saveManagedUser}>Guardar</button>
          </div>
        </div>
      </SimpleDialog>

      <DashboardLayout
        user={user}
        title="Dashboard do Gestor"
        subtitle={`Bem-vindo de volta, ${user.nome}!`}
        menuItems={menuItems}
        activeMenu={activeMenu}
        onSelectMenu={setActiveMenu}
        onLogout={onLogout}
        alertCount={alerts.length}
        avatarClass="list-avatar manager"
      >
        {activeMenu === 'dashboard' ? (
          <>
            <div className="row g-4 mb-4">
              {[
                ['Membros da Equipa', String(usersList.length)],
                ['Incidentes Resolvidos', String(incidentsList.filter((item) => item.status === 'Resolvido').length)],
                ['Incidentes Pendentes', String(incidentsList.filter((item) => item.status !== 'Resolvido').length)],
                ['Taxa de Resolução', usersList.length ? '95%' : '0%'],
              ].map(([title, value]) => (
                <div className="col-md-6 col-xl-3" key={title}>
                  <div className="card shadow-sm border-0 h-100">
                    <div className="card-body">
                      <div className="text-muted small mb-2">{title}</div>
                      <div className="fs-3 fw-semibold">{value}</div>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="card shadow-sm border-0">
              <div className="card-body">
                <h3 className="h5 mb-1">Incidentes Recentes</h3>
                <p className="text-muted small mb-4">Últimas atividades da equipa</p>
                <div className="d-grid gap-3">
                  {incidentsList.map((incident) => (
                    <div className="admin-list-row" key={incident.id}>
                      <div className="flex-grow-1">
                        <div className="fw-medium">{incident.title}</div>
                        <div className="small text-muted">{incident.assignee} • {incident.date}</div>
                      </div>
                      <span className="badge text-bg-secondary">{incident.status}</span>
                      <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(incident)}>Ver Detalhes</button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </>
        ) : null}

        {activeMenu === 'team' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <h3 className="h5 mb-3">Membros da Equipa</h3>
              <div className="d-grid gap-3">
                {usersList.map((member) => (
                  <div className="admin-list-row" key={member.id}>
                    <div className="list-avatar manager">{member.name.charAt(0)}</div>
                    <div className="flex-grow-1">
                      <div className="fw-medium">{member.name}</div>
                      <div className="small text-muted">{member.email}</div>
                    </div>
                    <div className="text-center small"><div className="text-muted">Concluídas</div><div className="fw-semibold">{member.ticketsOpen}</div></div>
                    <div className="text-center small"><div className="text-muted">Ativas</div><div className="fw-semibold">{member.status}</div></div>
                    <div className="text-center small"><div className="text-muted">Performance</div><div className="fw-semibold text-success">{member.department || 'N/A'}</div></div>
                    <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(member)}>Ver Perfil</button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'users' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <div>
                  <h3 className="h5 mb-1">Gestão de Utilizadores</h3>
                  <p className="text-muted small mb-0">Visualizar e gerir utilizadores do sistema</p>
                </div>
              </div>
              <div className="d-grid gap-3">
                {usersList.map((item) => (
                  <div className="admin-list-row" key={item.id}>
                    <div className="list-avatar user">{item.name.charAt(0)}</div>
                    <div className="flex-grow-1">
                      <div className="fw-medium">{item.name}</div>
                      <div className="small text-muted">{item.email}</div>
                      <div className="small text-muted">Departamento: {item.username}</div>
                    </div>
                    <div className="text-center small"><div className="text-muted">Tickets</div><div className="fw-semibold">{item.ticketsOpen}</div></div>
                    <div className="small text-muted">{item.lastActive}</div>
                    <div className="d-flex gap-2">
                      <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(item)}>Ver Detalhes</button>
                      <button className="btn btn-sm btn-outline-primary" onClick={() => openManageUser(item)}>Gerir</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'incidents' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <div>
                  <h3 className="h5 mb-1">Gestão de Incidentes</h3>
                  <p className="text-muted small mb-0">Gerir e resolver incidentes de segurança</p>
                </div>
              </div>
              <div className="d-grid gap-3">
                {incidentsList.map((item) => (
                  <div className="admin-list-row" key={item.id}>
                    <div className="flex-grow-1">
                      <div className="fw-medium">{item.title}</div>
                      <div className="small text-muted">Atribuído a: {item.assignee} • {item.date}</div>
                    </div>
                    <span className="badge text-bg-secondary">{item.status}</span>
                    <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(item)}>Ver Detalhes</button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'alerts' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <h3 className="h5 mb-3">Alertas</h3>
              <div className="d-grid gap-3">
                {alerts.map((alert) => (
                  <div className="alert-row" key={alert.id}>
                    <span className={`alert-dot ${alert.type === 'Crítico' ? 'critical' : alert.type === 'Aviso' ? 'warning' : 'info'}`}></span>
                    <div className="flex-grow-1">
                      <div>{alert.message}</div>
                      <div className="small text-muted mt-1">{alert.source} • {alert.time}</div>
                    </div>
                    <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(alert)}>Investigar</button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'reports' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <div>
                  <h3 className="h5 mb-1">Relatórios da Equipa</h3>
                  <p className="text-muted small mb-0">Exportação de dados da sua equipa e incidentes</p>
                </div>
              </div>
              <div className="d-grid gap-3">
                {[
                  {
                    tipo: 'mensal',
                    nome: 'Relatório Mensal',
                    descricao: `Resumo do mês — equipa, tickets criados e estado de resolução`,
                    badge: 'HTML',
                    badgeColor: 'text-bg-primary',
                    btnLabel: 'Abrir',
                  },
                  {
                    tipo: 'equipa',
                    nome: 'Performance da Equipa',
                    descricao: 'Lista de membros com emails, departamentos e contagem de tickets',
                    badge: 'CSV',
                    badgeColor: 'text-bg-success',
                    btnLabel: 'Exportar',
                  },
                  {
                    tipo: 'vulnerabilidades',
                    nome: 'Análise de Vulnerabilidades',
                    descricao: 'Tickets de prioridade Alta e Crítica da equipa',
                    badge: 'CSV',
                    badgeColor: 'text-bg-success',
                    btnLabel: 'Exportar',
                  },
                  {
                    tipo: 'resolvidos',
                    nome: 'Incidentes Resolvidos',
                    descricao: 'Histórico completo de tickets fechados pela equipa',
                    badge: 'CSV',
                    badgeColor: 'text-bg-success',
                    btnLabel: 'Exportar',
                  },
                ].map(({ tipo, nome, descricao, badge, badgeColor, btnLabel }) => (
                  <div className="settings-row" key={tipo}>
                    <div>
                      <div className="fw-medium">{nome}</div>
                      <div className="small text-muted">{descricao}</div>
                    </div>
                    <div className="d-flex gap-2 align-items-center">
                      <span className={`badge ${badgeColor}`}>{badge}</span>
                      <button
                        className="btn btn-outline-primary btn-sm"
                        disabled={managerReportLoading === tipo}
                        onClick={() => handleManagerReport(tipo)}
                      >
                        {managerReportLoading === tipo ? 'A gerar...' : btnLabel}
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              {usersList.length === 0 && (
                <div className="alert alert-info mt-4 mb-0 small">
                  Ainda não tem membros na equipa. Os relatórios CSV estarão vazios até adicionar utilizadores.
                </div>
              )}
            </div>
          </div>
        ) : null}

        {activeMenu === 'chat' ? <ManagerChatSection user={user} /> : null}
      </DashboardLayout>
    </>
  );
}

function UserDashboard({ user, onLogout }) {
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [showNewTicketDialog, setShowNewTicketDialog] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);
  const [activeCourse, setActiveCourse] = useState(null);
  const [newTicketData, setNewTicketData] = useState({ title: '', description: '', priority: 'Baixa' });
  const [ticketsList, setTicketsList] = useState([]);
  const [coursesList, setCoursesList] = useState([
    { id: 1, title: 'Segurança de Senhas', progress: 100, duration: '30 min', status: 'Concluído' },
    { id: 2, title: 'Phishing e Engenharia Social', progress: 100, duration: '45 min', status: 'Concluído' },
    { id: 3, title: 'Proteção de Dados Pessoais', progress: 65, duration: '60 min', status: 'Em Progresso' },
    { id: 4, title: 'Navegação Segura na Internet', progress: 0, duration: '40 min', status: 'Não Iniciado' },
  ]);

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard' },
    { id: 'tickets', label: 'Meus Tickets' },
    { id: 'chat', label: 'Chat' },
    { id: 'help', label: 'Ajuda' },
  ];

  useEffect(() => {
    const loadTickets = async () => {
      try {
        const response = await api.get(`/tickets?perfil=user&userId=${user.id}`);
        setTicketsList(response.data.data || []);
      } catch (error) {
        console.error(error);
      }
    };

    loadTickets();
  }, [user.id]);

  const createTicket = async () => {
    if (!newTicketData.title.trim()) return;
    try {
      const response = await api.post('/tickets', {
        titulo: newTicketData.title.trim(),
        descricao: newTicketData.description.trim(),
        prioridade: newTicketData.priority,
        createdBy: user.id,
      });
      setTicketsList((current) => [response.data.data, ...current]);
      setNewTicketData({ title: '', description: '', priority: 'Baixa' });
      setShowNewTicketDialog(false);
    } catch (error) {
      console.error(error);
    }
  };

  const openCourse = (course) => {
    const nextStatus = course.status === 'Não Iniciado' ? 'Em Progresso' : course.status;
    const nextProgress = course.status === 'Não Iniciado' ? 5 : course.progress;
    setCoursesList((current) => current.map((item) => (
      item.id === course.id ? { ...item, status: nextStatus, progress: nextProgress } : item
    )));
    setActiveCourse({ ...course, status: nextStatus, progress: nextProgress });
  };

  const progressCourse = () => {
    if (!activeCourse) return;
    const nextProgress = Math.min(activeCourse.progress + 20, 100);
    const nextStatus = nextProgress === 100 ? 'Concluído' : 'Em Progresso';
    setCoursesList((current) => current.map((item) => (
      item.id === activeCourse.id ? { ...item, progress: nextProgress, status: nextStatus } : item
    )));
    setActiveCourse({ ...activeCourse, progress: nextProgress, status: nextStatus });
  };

  return (
    <>
      <DetailModal item={selectedItem} title="Detalhes" onClose={() => setSelectedItem(null)} />

      <SimpleDialog show={showNewTicketDialog} title="Criar Novo Ticket" description="Descreva o seu problema ou pedido" onClose={() => setShowNewTicketDialog(false)}>
        <div className="d-grid gap-3">
          <input className="form-control" placeholder="Assunto" value={newTicketData.title} onChange={(e) => setNewTicketData({ ...newTicketData, title: e.target.value })} />
          <textarea className="form-control" rows="4" placeholder="Descrição" value={newTicketData.description} onChange={(e) => setNewTicketData({ ...newTicketData, description: e.target.value })}></textarea>
          <select className="form-select" value={newTicketData.priority} onChange={(e) => setNewTicketData({ ...newTicketData, priority: e.target.value })}>
            <option>Baixa</option>
            <option>Média</option>
            <option>Alta</option>
          </select>
          <div className="d-flex gap-2 justify-content-end">
            <button className="btn btn-outline-secondary" onClick={() => setShowNewTicketDialog(false)}>Cancelar</button>
            <button className="btn btn-primary" onClick={createTicket}>Submeter Ticket</button>
          </div>
        </div>
      </SimpleDialog>

      <SimpleDialog show={Boolean(activeCourse)} title={activeCourse?.title} description="Conteúdo do Curso" onClose={() => setActiveCourse(null)}>
        {activeCourse ? (
          <div className="d-grid gap-3">
            <div className="d-flex justify-content-between small text-muted">
              <span>Duração: {activeCourse.duration}</span>
              <span>{activeCourse.progress}% completo</span>
            </div>
            <div className="progress" style={{ height: 12 }}>
              <div className="progress-bar" style={{ width: `${activeCourse.progress}%` }}></div>
            </div>
            <div className="detail-box">
              Este módulo aborda os principais conceitos de <strong>{activeCourse.title}</strong>, com exemplos práticos e boas práticas de segurança.
            </div>
            {activeCourse.status !== 'Concluído' ? <button className="btn btn-primary" onClick={progressCourse}>Avançar no Curso (+20%)</button> : null}
          </div>
        ) : null}
      </SimpleDialog>

      <DashboardLayout
        user={user}
        title="Dashboard do Utilizador"
        subtitle={`Bem-vindo de volta, ${user.nome}!`}
        menuItems={menuItems}
        activeMenu={activeMenu}
        onSelectMenu={setActiveMenu}
        onLogout={onLogout}
        avatarClass="list-avatar user"
      >
        {activeMenu === 'dashboard' ? (
          <>
            <div className="row g-4 mb-4">
              {[
                ['Tickets Abertos', String(ticketsList.filter((item) => item.status === 'Aberto').length)],
                ['Tickets Resolvidos', String(ticketsList.filter((item) => item.status === 'Resolvido').length)],
                ['Cursos Concluídos', String(coursesList.filter((item) => item.status === 'Concluído').length)],
              ].map(([title, value]) => (
                <div className="col-md-4" key={title}>
                  <div className="card shadow-sm border-0 h-100">
                    <div className="card-body">
                      <div className="text-muted small mb-2">{title}</div>
                      <div className="fs-3 fw-semibold">{value}</div>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="card shadow-sm border-0 mb-4">
              <div className="card-body">
                <div className="d-flex justify-content-between align-items-center mb-4">
                  <div>
                    <h3 className="h5 mb-1">Meus Tickets Recentes</h3>
                    <p className="text-muted small mb-0">Acompanhe o estado dos seus pedidos</p>
                  </div>
                  <button className="btn btn-primary" onClick={() => setShowNewTicketDialog(true)}>Novo Ticket</button>
                </div>
                <div className="d-grid gap-3">
                  {ticketsList.slice(0, 3).map((ticket) => (
                    <div className="admin-list-row" key={ticket.id}>
                      <div className="flex-grow-1">
                        <div className="fw-medium">#{ticket.id} - {ticket.title}</div>
                        <div className="small text-muted">Criado: {ticket.created}</div>
                      </div>
                      <span className="badge text-bg-secondary">{ticket.status}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
            
  <div className="card shadow-sm border-0">
              <div className="card-body">
                <h3 className="h5 mb-3">Dicas de Segurança</h3>
                <div className="row g-3">
                  {[
                    ['Use senhas fortes', 'Combine letras maiúsculas, minúsculas, números e símbolos.'],
                    ['Ative a autenticação de dois fatores', 'Adicione uma camada extra de segurança às suas contas.'],
                    ['Não partilhe informações sensíveis', 'Nunca envie senhas ou dados confidenciais por email.'],
                    ['Mantenha o software atualizado', 'Instale atualizações de segurança regularmente.'],
                  ].map(([title, description]) => (
                    <div className="col-md-6" key={title}>
                      <div className="detail-box">
                        <div className="fw-medium">{title}</div>
                        <div className="small text-muted">{description}</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </>
        ) : null}

        {activeMenu === 'tickets' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center mb-4">
                <div>
                  <h3 className="h5 mb-1">Meus Tickets</h3>
                  <p className="text-muted small mb-0">Gerir todos os seus pedidos de suporte</p>
                </div>
                <button className="btn btn-primary" onClick={() => setShowNewTicketDialog(true)}>Criar Novo Ticket</button>
              </div>
              <div className="d-grid gap-3">
                {ticketsList.map((ticket) => (
                  <div className="admin-list-row" key={ticket.id}>
                    <div className="flex-grow-1">
                      <div className="fw-medium">#{ticket.id} - {ticket.title}</div>
                      <div className="small text-muted">Prioridade: {ticket.priority} • Atualizado: {ticket.updated}</div>
                    </div>
                    <span className="badge text-bg-secondary">{ticket.status}</span>
                    <button className="btn btn-sm btn-outline-secondary" onClick={() => setSelectedItem(ticket)}>Ver Detalhes</button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : null}

        {activeMenu === 'chat' ? <UserChatSection user={user} /> : null}

        {activeMenu === 'help' ? (
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <h3 className="h5 mb-3">Centro de Ajuda</h3>
              <div className="d-grid gap-3">
                {[
                  ['Como reportar um incidente de segurança?', 'Crie um novo ticket com prioridade Alta e descreva detalhadamente o incidente.'],
                ].map(([question, answer]) => (
                  <details className="detail-box" key={question}>
                    <summary>{question}</summary>
                    <p className="small text-muted mt-3 mb-0">{answer}</p>
                  </details>
                ))}
              </div>
            </div>
          </div>
        ) : null}
      </DashboardLayout>
    </>
  );
}

export default function App() {
  const [user, setUser] = useState(null);
  const [showLogin, setShowLogin] = useState(false);

  if (!user) {
    return (
      <>
        <HomeScreen onOpenLogin={() => setShowLogin(true)} />
        <LoginModal show={showLogin} onClose={() => setShowLogin(false)} onLogin={(loggedUser) => { setUser(loggedUser); setShowLogin(false); }} />
      </>
    );
  }

  if (user.perfil === 'admin') {
    return <AdminDashboard user={user} onLogout={() => setUser(null)} />;
  }

  if (user.perfil === 'manager') {
    return <ManagerDashboard user={user} onLogout={() => setUser(null)} />;
  }

  return <UserDashboard user={user} onLogout={() => setUser(null)} />;
}
